import SwiftUI
import UIKit

struct ZoomableComicImage: View {
    let image: UIImage
    let imageID: AnyHashable

    var body: some View {
        GeometryReader { proxy in
            ZoomableComicImageRepresentable(
                image: image,
                imageID: imageID,
                availableSize: proxy.size
